   153→type LeveledCompactorOptions struct {
   154→	// PE specifies the postings encoder. It is called when compactor is writing out the postings for a label name/value pair during compaction.
   155→	// If it is nil then the default encoder is used. At the moment that is the "raw" encoder. See index.EncodePostingsRaw for more.
   156→	PE index.PostingsEncoder
   157→	// MaxBlockChunkSegmentSize is the max block chunk segment size. If it is 0 then the default chunks.DefaultChunkSegmentSize is used.
   158→	MaxBlockChunkSegmentSize int64
   159→	// MergeFunc is used for merging series together in vertical compaction. By default storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge) is used.
   160→	MergeFunc storage.VerticalChunkSeriesMergeFunc
   161→	// EnableOverlappingCompaction enables compaction of overlapping blocks. In Prometheus it is always enabled.
   162→	// It is useful for downstream projects like Mimir, Cortex, Thanos where they have a separate component that does compaction.
   163→	EnableOverlappingCompaction bool
   164→}
