   181→func NewLeveledCompactorWithOptions(ctx context.Context, r prometheus.Registerer, l log.Logger, ranges []int64, pool chunkenc.Pool, opts LeveledCompactorOptions) (*LeveledCompactor, error) {
   182→	if len(ranges) == 0 {
   183→		return nil, fmt.Errorf("at least one range must be provided")
   184→	}
   185→	if pool == nil {
   186→		pool = chunkenc.NewPool()
   187→	}
   188→	if l == nil {
   189→		l = log.NewNopLogger()
   190→	}
   191→	mergeFunc := opts.MergeFunc
   192→	if mergeFunc == nil {
   193→		mergeFunc = storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge)
   194→	}
   195→	maxBlockChunkSegmentSize := opts.MaxBlockChunkSegmentSize
   196→	if maxBlockChunkSegmentSize == 0 {
   197→		maxBlockChunkSegmentSize = chunks.DefaultChunkSegmentSize
   198→	}
   199→	pe := opts.PE
   200→	if pe == nil {
   201→		pe = index.EncodePostingsRaw
   202→	}
   203→	return &LeveledCompactor{
   204→		ranges:                      ranges,
   205→		chunkPool:                   pool,
   206→		logger:                      l,
   207→		metrics:                     NewCompactorMetrics(r),
   208→		ctx:                         ctx,
   209→		maxBlockChunkSegmentSize:    maxBlockChunkSegmentSize,
   210→		mergeFunc:                   mergeFunc,
   211→		postingsEncoder:             pe,
   212→		enableOverlappingCompaction: opts.EnableOverlappingCompaction,
   213→	}, nil
   214→}
