   289→// selectDirs returns the dir metas that should be compacted into a single new block.
   290→// If only a single block range is configured, the result is always nil.
   291→func (c *LeveledCompactor) selectDirs(ds []dirMeta) []dirMeta {
   292→	if len(c.ranges) < 2 || len(ds) < 1 {
   293→		return nil
   294→	}
   295→
   296→	highTime := ds[len(ds)-1].meta.MinTime
   297→
   298→	for _, iv := range c.ranges[1:] {
   299→		parts := splitByRange(ds, iv)
   300→		if len(parts) == 0 {
   301→			continue
   302→		}
   303→
   304→	Outer:
   305→		for _, p := range parts {
   306→			// Do not select the range if it has a block whose compaction failed.
   307→			for _, dm := range p {
   308→				if dm.meta.Compaction.Failed {
   309→					continue Outer
   310→				}
   311→			}
   312→
   313→			mint := p[0].meta.MinTime
   314→			maxt := p[len(p)-1].meta.MaxTime
   315→			// Pick the range of blocks if it spans the full range (potentially with gaps)
   316→			// or is before the most recent block.
   317→			// This ensures we don't compact blocks prematurely when another one of the same
   318→			// size still fits in the range.
   319→			if (maxt-mint == iv || maxt <= highTime) && len(p) > 1 {
   320→				return p
   321→			}
   322→		}
   323→	}
   324→
   325→	return nil
   326→}
   327→
   328→// selectOverlappingDirs returns all dirs with overlapping time ranges.
   329→// It expects sorted input by mint and returns the overlapping dirs in the same order as received.
   330→func (c *LeveledCompactor) selectOverlappingDirs(ds []dirMeta) []string {
   331→	if !c.enableOverlappingCompaction {
   332→		return nil
   333→	}
   334→	if len(ds) < 2 {
   335→		return nil
   336→	}
   337→	var overlappingDirs []string
   338→	globalMaxt := ds[0].meta.MaxTime
   339→	for i, d := range ds[1:] {
   340→		if d.meta.MinTime < globalMaxt {
   341→			if len(overlappingDirs) == 0 { // When it is the first overlap, need to add the last one as well.
   342→				overlappingDirs = append(overlappingDirs, ds[i].dir)
   343→			}
   344→			overlappingDirs = append(overlappingDirs, d.dir)
   345→		} else if len(overlappingDirs) > 0 {
   346→			break
   347→		}
   348→		if d.meta.MaxTime > globalMaxt {
   349→			globalMaxt = d.meta.MaxTime
   350→		}
   351→	}
   352→	return overlappingDirs
   353→}
   354→
   355→// splitByRange splits the directories by the time range. The range sequence starts at 0.
   356→//
   357→// For example, if we have blocks [0-10, 10-20, 50-60, 90-100] and the split range tr is 30
   358→// it returns [0-10, 10-20], [50-60], [90-100].
   359→func splitByRange(ds []dirMeta, tr int64) [][]dirMeta {
   360→	var splitDirs [][]dirMeta
   361→
   362→	for i := 0; i < len(ds); {
   363→		var (
   364→			group []dirMeta
   365→			t0    int64
   366→			m     = ds[i].meta
   367→		)
   368→		// Compute start of aligned time range of size tr closest to the current block's start.
   369→		if m.MinTime >= 0 {
   370→			t0 = tr * (m.MinTime / tr)
   371→		} else {
   372→			t0 = tr * ((m.MinTime - tr + 1) / tr)
   373→		}
   374→		// Skip blocks that don't fall into the range. This can happen via mis-alignment or
   375→		// by being the multiple of the intended range.
   376→		if m.MaxTime > t0+tr {
   377→			i++
   378→			continue
   379→		}
   380→
   381→		// Add all dirs to the current group that are within [t0, t0+tr].
   382→		for ; i < len(ds); i++ {
   383→			// Either the block falls into the next range or doesn't fit at all (checked above).
   384→			if ds[i].meta.MaxTime > t0+tr {
   385→				break
   386→			}
   387→			group = append(group, ds[i])
   388→		}
   389→
   390→		if len(group) > 0 {
   391→			splitDirs = append(splitDirs, group)
   392→		}
   393→	}
   394→
   395→	return splitDirs
   396→}
