    30→// repairBadIndexVersion repairs an issue in index and meta.json persistence introduced in
    31→// commit 129773b41a565fde5156301e37f9a87158030443.
    32→func repairBadIndexVersion(logger log.Logger, dir string) error {
    33→	// All blocks written by Prometheus 2.1 with a meta.json version of 2 are affected.
    34→	// We must actually set the index file version to 2 and revert the meta.json version back to 1.
    35→	dirs, err := blockDirs(dir)
    36→	if err != nil {
    37→		return fmt.Errorf("list block dirs in %q: %w", dir, err)
    38→	}
    39→
    40→	tmpFiles := make([]string, 0, len(dirs))
    41→	defer func() {
    42→		for _, tmp := range tmpFiles {
    43→			if err := os.RemoveAll(tmp); err != nil {
    44→				level.Error(logger).Log("msg", "remove tmp file", "err", err.Error())
    45→			}
    46→		}
    47→	}()
    48→
    49→	for _, d := range dirs {
    50→		meta, err := readBogusMetaFile(d)
    51→		if err != nil {
    52→			level.Error(logger).Log("msg", "failed to read meta.json for a block during repair process; skipping", "dir", d, "err", err)
    53→			continue
    54→		}
    55→		if meta.Version == metaVersion1 {
    56→			level.Info(logger).Log(
    57→				"msg", "Found healthy block",
    58→				"mint", meta.MinTime,
    59→				"maxt", meta.MaxTime,
    60→				"ulid", meta.ULID,
    61→			)
    62→			continue
    63→		}
    64→		level.Info(logger).Log(
    65→			"msg", "Fixing broken block",
    66→			"mint", meta.MinTime,
    67→			"maxt", meta.MaxTime,
    68→			"ulid", meta.ULID,
    69→		)
    70→
    71→		repl, err := os.Create(filepath.Join(d, "index.repaired"))
    72→		if err != nil {
    73→			return fmt.Errorf("create index.repaired for block dir: %v: %w", d, err)
    74→		}
    75→		tmpFiles = append(tmpFiles, repl.Name())
    76→
    77→		broken, err := os.Open(filepath.Join(d, indexFilename))
    78→		if err != nil {
    79→			return fmt.Errorf("open broken index for block dir: %v: %w", d, err)
    80→		}
    81→		if _, err := io.Copy(repl, broken); err != nil {
    82→			return fmt.Errorf("copy content of index to index.repaired for block dir: %v: %w", d, err)
    83→		}
    84→
    85→		// Set the 5th byte to 2 to indicate the correct file format version.
    86→		if _, err := repl.WriteAt([]byte{2}, 4); err != nil {
    87→			errs := tsdb_errors.NewMulti(
    88→				fmt.Errorf("rewrite of index.repaired for block dir: %v: %w", d, err))
    89→			if err := repl.Close(); err != nil {
    90→				errs.Add(fmt.Errorf("close: %w", err))
    91→			}
    92→			return errs.Err()
    93→		}
    94→		if err := repl.Sync(); err != nil {
    95→			errs := tsdb_errors.NewMulti(
    96→				fmt.Errorf("sync of index.repaired for block dir: %v: %w", d, err))
    97→			if err := repl.Close(); err != nil {
    98→				errs.Add(fmt.Errorf("close: %w", err))
    99→			}
   100→			return errs.Err()
   101→		}
   102→		if err := repl.Close(); err != nil {
   103→			return fmt.Errorf("close repaired index for block dir: %v: %w", d, err)
   104→		}
   105→		if err := broken.Close(); err != nil {
   106→			if err := repl.Close(); err != nil {
   107→				return fmt.Errorf("close broken index for block dir: %v: %w", d, err)
   108→			}
   109→		}
   110→		if err := fileutil.Replace(repl.Name(), broken.Name()); err != nil {
   111→			if err := repl.Close(); err != nil {
   112→				return fmt.Errorf("replaced broken index with index.repaired for block dir: %v: %w", d, err)
   113→			}
   114→		}
   115→		// Reset version of meta.json to 1.
   116→		meta.Version = metaVersion1
   117→		if _, err := writeMetaFile(logger, d, meta); err != nil {
   118→			if err := repl.Close(); err != nil {
   119→				return fmt.Errorf("write meta for block dir: %v: %w", d, err)
   120→			}
   121→		}
   122→	}
   123→	return nil
   124→}
   125→
   126→func readBogusMetaFile(dir string) (*BlockMeta, error) {
   127→	b, err := os.ReadFile(filepath.Join(dir, metaFilename))
   128→	if err != nil {
   129→		return nil, err
   130→	}
   131→	var m BlockMeta
   132→
   133→	if err := json.Unmarshal(b, &m); err != nil {
   134→		return nil, err
   135→	}
   136→	if m.Version != metaVersion1 && m.Version != 2 {
   137→		return nil, fmt.Errorf("unexpected meta file version %d", m.Version)
   138→	}
   139→	return &m, nil
   140→}
